solution.javascript:
function diagonalSum(mat) {
  const n = mat.length;
  let sum = 0;

  for (let i = 0; i < n; i++) {
    sum += mat[i][i]; // Primary diagonal
    sum += mat[i][n - 1 - i]; // Secondary diagonal
  }

  // If odd size, subtract middle element (counted twice)
  if (n % 2 === 1) {
    sum -= mat[Math.floor(n / 2)][Math.floor(n / 2)];
  }

  return sum;
}

